from elasticsearch import Elasticsearch, RequestsHttpConnection
from requests.auth import HTTPBasicAuth
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Elasticsearch configuration
ELASTICSEARCH_HOST = 'localhost'
ELASTICSEARCH_PORT = 9200
ELASTICSEARCH_USER = 'elastic'
ELASTICSEARCH_PASSWORD = 'password'
ELASTICSEARCH_INDEX = 'user_feedback'

# Initialize Elasticsearch client
es = Elasticsearch(
    hosts=[{'host': ELASTICSEARCH_HOST, 'port': ELASTICSEARCH_PORT}],
    http_auth=HTTPBasicAuth(ELASTICSEARCH_USER, ELASTICSEARCH_PASSWORD),
    connection_class=RequestsHttpConnection
)

def create_index():
    """Create an Elasticsearch index for user feedback."""
    try:
        if not es.indices.exists(index=ELASTICSEARCH_INDEX):
            es.indices.create(index=ELASTICSEARCH_INDEX, body={
                "mappings": {
                    "properties": {
                        "user_id": {"type": "keyword"},
                        "feedback": {"type": "text"},
                        "timestamp": {"type": "date"},
                        "platform": {"type": "keyword"}
                    }
                }
            })
            logger.info(f"Index '{ELASTICSEARCH_INDEX}' created successfully.")
        else:
            logger.info(f"Index '{ELASTICSEARCH_INDEX}' already exists.")
    except Exception as e:
        logger.error(f"Error creating index: {str(e)}")

if __name__ == '__main__':
    create_index()

